// Nome: Preparar dados para Apps Script
// Descrição: Combina dados do webhook com campos formatados para substituição

// Obter dados do webhook original
const webhookData = $('Webhook').item.json.body;

// Obter campos processados do Edit Fields
const camposOriginais = $input.first().json;

// Validar dados essenciais
if (!webhookData || !webhookData.modelo || !webhookData.blocos) {
  throw new Error('Payload inválido - faltam dados essenciais');
}

// Separar campo de fonte dos demais
const fontePadrao = camposOriginais.fonte_letra || null;
delete camposOriginais.fonte_letra; // Remove para não virar tag

// Formatar campos com as tags {{}}
const camposFormatados = {};
for (const [campo, valor] of Object.entries(camposOriginais)) {
  const tag = `{{${campo}}}`;
  camposFormatados[tag] = valor || '';
}

// Preparar dados para Apps Script
const dadosParaScript = {
  body: {
    processo: webhookData.processo,
    modelo: webhookData.modelo,
    blocos: webhookData.blocos || [],
    jurisprudencias: webhookData.jurisprudencias || [],
    campos_substituicao: camposFormatados,
    configuracao_fonte: fontePadrao // Campo separado para configuração
  }
};

// Log para debug
console.log('Payload preparado para Apps Script');
console.log('Total de campos para substituir:', Object.keys(camposFormatados).length);
if (fontePadrao) {
  console.log('Fonte configurada:', fontePadrao);
}

return {
  json: dadosParaScript
};

// Este Code node assume que você tem 1 item vindo dos nós anteriores
// e que você pode acessar os dados do cliente e da empresa.
// Ajuste os caminhos se necessário.

