  // tenta encontrar endereço no mesmo estado
  const match = enderecos.find(e => (e?.estado || '').toUpperCase() === ufCliente);

  // se não houver endereço no estado, pega o primeiro disponível
  const escolhido = match || enderecos[0] || null;

  return {
    json: {
      ...item.json,
      empresa_endereco: escolhido ? (escolhido.endereco || '') : ''
    }
  };
});

