// Descrição: Combina dados do webhook com campos formatados para substituição

// Obter dados do webhook original
const webhookData = $('Webhook').item.json.body;

// Obter campos processados do Edit Fields
const camposOriginais = $input.first().json;

// Validar dados essenciais
if (!webhookData || !webhookData.modelo || !webhookData.blocos) {
  throw new Error('Payload inválido - faltam dados essenciais');
}

// Separar campo de fonte dos demais
const fontePadrao = camposOriginais.fonte_letra || null;
delete camposOriginais.fonte_letra; // Remove para não virar tag

// Formatar campos com as tags {{}}
const camposFormatados = {};
for (const [campo, valor] of Object.entries(camposOriginais)) {
  const tag = `{{${campo}}}`;
  camposFormatados[tag] = valor || '';
}

// Preparar dados para Apps Script
const dadosParaScript = {
  body: {
    processo: webhookData.processo,
    modelo: webhookData.modelo,
    blocos: webhookData.blocos || [],
    jurisprudencias: webhookData.jurisprudencias || [],
    campos_substituicao: camposFormatados,
    configuracao_fonte: fontePadrao // Campo separado para configuração
  }
};

// Log para debug
console.log('Payload preparado para Apps Script');
console.log('Total de campos para substituir:', Object.keys(camposFormatados).length);
if (fontePadrao) {
  console.log('Fonte configurada:', fontePadrao);
}

return {
  json: dadosParaScript
};

// Este Code node assume que você tem 1 item vindo dos nós anteriores
// e que você pode acessar os dados do cliente e da empresa.
// Ajuste os caminhos se necessário.

return $input.all().map(item => {
  const cliente  = $(':Clientes1').item.json;   // pega do node Clientes
  const empresa  = $(':Empresas1').item.json;   // pega do node Empresas

  const ufCliente = (cliente?.estado || '').toUpperCase();
  const enderecos = empresa?.enderecos_empresa?.enderecos || [];

  // tenta encontrar endereço no mesmo estado
  const match = enderecos.find(e => (e?.estado || '').toUpperCase() === ufCliente);

  // se não houver endereço no estado, pega o primeiro disponível
  const escolhido = match || enderecos[0] || null;

  return {
    json: {
      ...item.json,
      empresa_endereco: escolhido ? (escolhido.endereco || '') : ''
    }
  };
});

// Nome do seu nó de gatilho. O padrão é 'Webhook'.
// Se você renomeou seu nó, altere esta variável.
const NOME_DO_NO_WEBHOOK = 'Webhook';

// Pega os dados diretamente do nó Webhook para garantir que temos a estrutura original.
const webhookData = $(NOME_DO_NO_WEBHOOK).item;

// --- VERIFICAÇÃO DE SEGURANÇA ---
// Garante que os dados do webhook foram encontrados e têm a estrutura esperada.
if (!webhookData || !webhookData.json || !webhookData.json.body) {
  throw new Error(`ERRO: Não foi possível encontrar a propriedade 'body' nos dados do nó '${NOME_DO_NO_WEBHOOK}'. Verifique se o nome do nó está correto e se o webhook está recebendo dados.`);
}

const payload = webhookData.json.body;

// --- EXTRAÇÃO DOS IDs ---
const todosOsBlocos = payload.blocos || [];
const todasAsJurisprudencias = payload.jurisprudencias || [];
const idsUnicos = new Set();

// 1. Adiciona o ID do documento do modelo principal
if (payload.modelo && payload.modelo.google_doc_id) {
  idsUnicos.add(payload.modelo.google_doc_id);
}

// 2. Adiciona IDs dos blocos de texto e suas jurisprudências vinculadas
todosOsBlocos.forEach(bloco => {
  if (bloco.google_doc_id) {
    idsUnicos.add(bloco.google_doc_id);
  }
  if (bloco.jurisprudencias_vinculadas && Array.isArray(bloco.jurisprudencias_vinculadas)) {
    bloco.jurisprudencias_vinculadas.forEach(juris => {
      if (juris.google_doc_id) {
        idsUnicos.add(juris.google_doc_id);
      }
    });
  }
});

// 3. Adiciona IDs das jurisprudências do nível principal
todasAsJurisprudencias.forEach(juris => {
    if(juris.google_doc_id) {
        idsUnicos.add(juris.google_doc_id);
    }
});

// --- PREPARAÇÃO DA SAÍDA ---
// Transforma o conjunto de IDs únicos em um array de objetos,
// que é o formato que o N8N precisa para o próximo nó (o Loop).
const resultado = Array.from(idsUnicos).map(id => ({
  json: {
    google_doc_id: id
  }
}));

// Retorna a lista de IDs para ser usada pelo próximo nó.
return resultado;

// --- CONFIGURAÇÃO ---
// Verifique se os nomes dos nós correspondem ao seu cenário.
const NOME_DO_NO_WEBHOOK = 'Webhook';
const NOME_DO_NO_LOOP = 'Loop IDs dos Documentos'; // Certifique-se de que seu nó de Loop tem este nome.

// --- BUSCAR DADOS DE NÓS ANTERIORES ---
const webhookData = $(NOME_DO_NO_WEBHOOK).item;
const textosBuscados = $items(NOME_DO_NO_LOOP);

// --- VERIFICAÇÕES DE SEGURANÇA ---
if (!webhookData || !webhookData.json || !webhookData.json.body) {
  throw new Error(`ERRO: Não foi possível ler os dados do nó '${NOME_DO_NO_WEBHOOK}'.`);
}
if (!textosBuscados || textosBuscados.length === 0) {
  throw new Error(`ERRO: O nó '${NOME_DO_NO_LOOP}' não retornou nenhum texto de documento.`);
}

const payloadOriginal = webhookData.json.body;

// --- PROCESSAMENTO ---
// 1. Criar um "mapa" para consulta rápida dos textos (ID -> Texto)
const mapaDeTextos = new Map();
textosBuscados.forEach(item => {
  // CORREÇÃO AQUI: Usamos 'documentId' e 'content', que são os campos retornados pelo nó do Google Docs.
  if (item.json.documentId && item.json.content) {
    mapaDeTextos.set(item.json.documentId, item.json.content);
  }
});

// 2. "Hidratar" os blocos do payload original com o texto buscado.
const blocosHidratados = (payloadOriginal.blocos || []).map(bloco => {
  const texto_conteudo = mapaDeTextos.get(bloco.google_doc_id) || '';

  const jurisprudenciasHidratadas = (bloco.jurisprudencias_vinculadas || []).map(juris => ({
    ...juris,
    texto_conteudo: mapaDeTextos.get(juris.google_doc_id) || ''
  }));

  return {
    ...bloco,
    texto_conteudo: texto_conteudo,
    jurisprudencias_vinculadas: jurisprudenciasHidratadas
  };
});

// 3. "Hidratar" as jurisprudências do nível principal do payload
const jurisprudenciasPrincipaisHidratadas = (payloadOriginal.jurisprudencias || []).map(juris => ({
    ...juris,
    texto_conteudo: mapaDeTextos.get(juris.google_doc_id) || ''
}));

// 4. Montar o objeto final, que agora contém toda a informação necessária em um só lugar.
const payloadHidratado = {
  ...payloadOriginal,
  blocos: blocosHidratados,
  jurisprudencias: jurisprudenciasPrincipaisHidratadas
};

// --- SAÍDA ---
return [{
  json: payloadHidratado
}];

// --- NOTA IMPORTANTE ---
// Este código assume que, para um processo do tipo "órgão", o payload do Lovable
// enviará um array chamado "restricoes". Cada objeto nesse array terá os dados
// da restrição, a tag selecionada e o ID do bloco de impugnação selecionado.
// O payload de exemplo atual é do tipo "empresa". Estou adaptando o código
// para a estrutura que definimos para o tipo "órgão".

// Pega o payload "hidratado" do passo anterior.
const payload = $input.first().json;

// --- DADOS DE EXEMPLO (Simulando um payload real do tipo "órgão") ---
// Como o payload de teste atual não tem a estrutura de "restrições",
// vamos simular uma aqui para o código funcionar.
// NO CENÁRIO REAL, VOCÊ DEVE REMOVER OU COMENTAR ESTE BLOCO DE SIMULAÇÃO.
if (!payload.restricoes) {
  console.log("AVISO: Usando dados simulados de 'restricoes' para teste.");
  payload.restricoes = [
    { dados_restricao: { contrato: "111", valor: "1.500,00" }, tag_selecionada: "{{email}}", bloco_selecionado_id: "34555ba2-7539-40d5-9f90-19aee8e32ade" },
    { dados_restricao: { contrato: "222", valor: "850,00" }, tag_selecionada: "{{email}}", bloco_selecionado_id: "34555ba2-7539-40d5-9f90-19aee8e32ade" },
    { dados_restricao: { contrato: "333", valor: "2.100,00" }, tag_selecionada: "{{sms}}", bloco_selecionado_id: "767de523-b256-457a-97eb-6fe5b436cc95" }
  ];
}
// --- FIM DO BLOCO DE SIMULAÇÃO ---


// Objeto para agrupar as restrições por argumento (bloco de texto)
const gruposDeArgumentos = {};

// 1. Iterar sobre cada restrição para agrupá-las
for (const restricao of (payload.restricoes || [])) {
  const blocoId = restricao.bloco_selecionado_id;
  const tag = restricao.tag_selecionada.replace(/[{}]/g, ''); // Limpa a tag para usar como chave (ex: 'email')

  // Se este argumento (bloco) ainda não foi visto, inicialize o grupo
  if (!gruposDeArgumentos[blocoId]) {
    // Encontrar o bloco correspondente no payload para pegar o título e o texto
    const blocoInfo = payload.blocos.find(b => b.id === blocoId);
    if (!blocoInfo) continue; // Pula se não encontrar o bloco

    gruposDeArgumentos[blocoId] = {
      tag: tag,
      bloco_id: blocoId,
      titulo_subtopico: blocoInfo.titulo, // Título do bloco será o subtópico
      texto_base_singular: blocoInfo.texto_conteudo,
      restricoes_associadas: []
    };
  }
  // Adiciona os dados da restrição atual ao grupo correspondente
  gruposDeArgumentos[blocoId].restricoes_associadas.push(restricao.dados_restricao);
}

// 2. Transformar os grupos na estrutura final de Tópicos e Subtópicos
const topicos = {};

for (const blocoId in gruposDeArgumentos) {
  const grupo = gruposDeArgumentos[blocoId];
  const tag = grupo.tag;

  // Se o tópico principal (a tag) ainda não existe, crie-o
  if (!topicos[tag]) {
    topicos[tag] = {
      topico_principal: {
        tag_id: tag,
        // Transforma 'email' em 'DA(S) NOTIFICAÇÃO(ÕES) ENVIADA(S) POR E-MAIL'
        titulo: `DA(S) NOTIFICAÇÃO(ÕES) ENVIADA(S) POR ${tag.toUpperCase()}`
      },
      subtopicos: []
    };
  }

  // Adiciona o grupo como um subtópico dentro do tópico principal correspondente
  topicos[tag].subtopicos.push(grupo);
}

// 3. Converter o objeto de tópicos em um array, que é o formato final
const resultadoFinal = Object.values(topicos);

return resultadoFinal;
